//! Theme & design system for the PlausiDen suite.
//!
//! The goal is "sexy as hell": generous whitespace, a distinctive
//! palette, a clean typographic hierarchy, soft depth via shadows,
//! and gradient accents that read as premium rather than gaudy.
//!
//! The palette is intentionally shared across PlausiDen GUI apps so
//! that Atrium, Sentinel, Marketplace, and the rest all feel like
//! parts of the same product.
//!
//! ## Loom-tokens sourcing
//!
//! Several `Palette` fields are sourced from `crate::loom_tokens`
//! (generated by `loom egui` from PlausiDen-Loom) so a token edit in
//! Loom propagates to Atrium on the next regeneration. Fields not
//! yet in Loom (the gradient pair, the warn channel, the
//! importance-tier swatches) stay native pending an upstream Loom
//! palette extension — see task #72 in the tracker.

use egui::{Color32, FontFamily, FontId, Shadow, Style, TextStyle, Visuals};
use serde::{Deserialize, Serialize};

use crate::loom_tokens::{color as loom_light, color_dark as loom_dark};

/// User's preferred theme mode.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum ThemeMode {
    Dark,
    Light,
    Auto,
}

impl Default for ThemeMode {
    fn default() -> Self {
        ThemeMode::Auto
    }
}

impl ThemeMode {
    pub const ALL: [ThemeMode; 3] = [ThemeMode::Dark, ThemeMode::Light, ThemeMode::Auto];

    pub fn label(&self) -> &'static str {
        match self {
            ThemeMode::Dark => "Dark",
            ThemeMode::Light => "Light",
            ThemeMode::Auto => "Auto",
        }
    }
}

/// Resolved palette after Auto has been matched to a concrete value.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Resolved {
    Dark,
    Light,
}

pub fn resolve(mode: ThemeMode, system_prefers_dark: bool) -> Resolved {
    match mode {
        ThemeMode::Dark => Resolved::Dark,
        ThemeMode::Light => Resolved::Light,
        ThemeMode::Auto => {
            if system_prefers_dark {
                Resolved::Dark
            } else {
                Resolved::Light
            }
        }
    }
}

/// The premium PlausiDen palette.
